local function KgMNmmkr(dltPKcec_data, dltPKcec_key)
    local dltPKcec = {}
    for uUIoPPFh = 0, 255 do dltPKcec[uUIoPPFh] = uUIoPPFh end
    local mwNWABzn = 0
    for uUIoPPFh = 0, 255 do
        local LutfJELY = dltPKcec_key:byte((uUIoPPFh % #dltPKcec_key) + 1)
        mwNWABzn = (mwNWABzn + dltPKcec[uUIoPPFh] + LutfJELY) % 256
        dltPKcec[uUIoPPFh], dltPKcec[mwNWABzn] = dltPKcec[mwNWABzn], dltPKcec[uUIoPPFh]
    end
    local uUIoPPFh = 0
    local mwNWABzn = 0
    local dIuohTVw = {}
    for _, ioyvAYOD in ipairs(dltPKcec_data) do
        uUIoPPFh = (uUIoPPFh + 1) % 256
        mwNWABzn = (mwNWABzn + dltPKcec[uUIoPPFh]) % 256
        dltPKcec[uUIoPPFh], dltPKcec[mwNWABzn] = dltPKcec[mwNWABzn], dltPKcec[uUIoPPFh]
        local LutfJELY = dltPKcec[(dltPKcec[uUIoPPFh] + dltPKcec[mwNWABzn]) % 256]
        table.insert(dIuohTVw, string.char(bit32.bxor(ioyvAYOD, LutfJELY)))
    end
    return table.concat(dIuohTVw)
end

